@classmethod
def NewFromJsonDict(cls, data, **kwargs):
    """ Create a new instance based on a JSON dict. Any kwargs should be
    supplied by the inherited, calling class.

    Args:
        data: A JSON dict, as converted from the JSON in the twitter API.

    """
    if data is None:
        data = {}

    # Merge provided kwargs with the JSON data, letting explicit kwargs
    # override values from the JSON payload.
    init_kwargs = dict(data)
    init_kwargs.update(kwargs)

    return cls(**init_kwargs)

