class _MediaType:
    def __init__(self, media_type_str):
        self.orig = '' if (media_type_str is None) else media_type_str
        self.full_type, self.params = parse_header_parameters(self.orig)
        self.main_type, sep, self.sub_type = self.full_type.partition('/')

    def match(self, other):
        """Return true if this MediaType satisfies the given MediaType."""
        if other is None:
            return False

        # Exact match on type/subtype, with wildcard support.
        if self.main_type != '*' and other.main_type != '*' and self.main_type != other.main_type:
            return False

        if self.sub_type != '*' and other.sub_type != '*' and self.sub_type != other.sub_type:
            return False

        # All parameters in `other` must be present and equal in `self`.
        for key, value in other.params.items():
            if key not in self.params or self.params[key] != value:
                return False

        return True

@property
def precedence(self):
    """
    Return a precedence level from 0-3 for the media type given how specific it is.
    """
    if self.main_type == '*' and self.sub_type == '*':
        return 0
    if self.sub_type == '*':
        return 1
    if self.main_type == '*':
        return 1
    if self.params:
        return 3
    return 2

