def close(self, do_log=True):
    """
    Close the database connection.

    If this SqliteDict was created with a temporary filename, the file is
    removed on close.
    """
    if hasattr(self, 'conn') and self.conn is not None:
        try:
            self.conn.close()
        finally:
            self.conn = None

    if self.in_temp and self.filename and os.path.exists(self.filename):
        try:
            os.remove(self.filename)
        except OSError:
            if do_log:
                logger.exception("Could not remove temporary sqlite file %r", self.filename)

def __del__(self):
    try:
        self.close(do_log=False)
    except Exception:
        pass

