def should_flush(self):
    """
    Determine whether the current batch should be flushed.

    DynamoDB batch write requests can contain at most 25 operations.
    """
    return len(self._to_put) + len(self._to_delete) >= 25

def flush(self):
    """
    Send the current batch of put/delete requests to DynamoDB.
    """
    if not self._to_put and not self._to_delete:
        return

    request_items = []

    for item in self._to_put:
        request_items.append({'PutRequest': {'Item': item}})

    for item in self._to_delete:
        request_items.append({'DeleteRequest': {'Key': item}})

    self._to_put = []
    self._to_delete = []

    response = self.table.meta.client.batch_write_item(
        RequestItems={
            self.table.name: request_items
        }
    )

    self._unprocessed.extend(
        response.get('UnprocessedItems', {}).get(self.table.name, [])
    )

def resend_unprocessed(self):
    """
    Retry any unprocessed batch write requests until they are accepted.
    """
    while self._unprocessed:
        request_items = self._unprocessed
        self._unprocessed = []

        response = self.table.meta.client.batch_write_item(
            RequestItems={
                self.table.name: request_items
            }
        )

        self._unprocessed.extend(
            response.get('UnprocessedItems', {}).get(self.table.name, [])
        )

