@classmethod
def load(cls, dirname=None, locales=None, domain=DEFAULT_DOMAIN):
    """Load translations from the given directory.

    :param dirname: the directory containing the ``MO`` files
    :param locales: the list of locales in order of preference (items in
                    this list can be either `Locale` objects or locale
                    strings)
    :param domain: the message domain
    :return: the loaded catalog, or a ``NullTranslations`` instance if no
             matching translations were found
    :rtype: `Translations`
    """
    if locales is None:
        locales = []

    # Normalize locale values to strings
    locale_names = []
    for locale in locales:
        if hasattr(locale, 'language'):
            locale_names.append(str(locale))
        else:
            locale_names.append(str(locale))

    # Build candidate paths in preference order
    candidates = []
    for locale in locale_names:
        candidates.append(os.path.join(dirname, locale, 'LC_MESSAGES', '%s.mo' % domain))
        candidates.append(os.path.join(dirname, '%s.mo' % domain))

    # Try to load the first matching translation file
    for filename in candidates:
        if filename and os.path.exists(filename):
            with open(filename, 'rb') as fp:
                return cls(fp, domain=domain)

    return gettext.NullTranslations()

