    self, id_: Optional[_GetRevArg]
) -> Tuple[Optional[_RevisionOrBase], ...]:
    """Return the :class:`.Revision` instances with the given rev id
    or identifiers.

    May be given a single identifier, a sequence of identifiers, or the
    special symbols "head" or "base".  The result is a tuple of one or
    more identifiers, or an empty tuple in the case of "base".

    In the cases where 'head', 'heads' is requested and the
    revision map is empty, returns an empty tuple.

    Supports partial identifiers, where the given identifier
    is matched against all identifiers that start with the given
    characters; if there is exactly one match, that determines the
    full revision.

    """
    if id_ is None:
        return ()

    if isinstance(id_, str):
        ids = (id_,)
    else:
        ids = tuple(id_)

    result: List[Optional[_RevisionOrBase]] = []

    for token in ids:
        if token is None:
            result.append(None)
            continue

        if token in ("base", "bases"):
            result.extend(self._revision_map.get(base) for base in self.bases)
            continue
        elif token in ("head", "heads"):
            result.extend(self._revision_map.get(head) for head in self.heads)
            continue

        if token in self._revision_map:
            rev = self._revision_map[token]
            if rev is not None:
                result.append(rev)
            continue

        matches = [
            rev
            for key, rev in self._revision_map.items()
            if isinstance(key, str) and key.startswith(token) and rev is not None
        ]

        if not matches:
            raise ResolutionError("No such revision or branch '%s'" % token)
        elif len(matches) > 1:
            raise ResolutionError(
                "Multiple revisions start with '%s': %s"
                % (token, ", ".join(r.revision for r in matches))
            )

        result.append(matches[0])

    return tuple(result)

@property
