    return util.to_tuple(self.down_revision) + util.to_tuple(self.dependencies)

@property
def _versioned_down_revisions(self) -> Tuple[str, ...]:
    """Return only the versioned down revisions.

    This excludes ``dependencies`` and is used for normal revision
    traversal relationships.
