def from_page_data(cls, tree_conf: TreeConf, data: bytes,
                   page: int=None) -> 'Node':
    node_type = data[0]

    if node_type == 1:
        return LonelyRootNode(tree_conf, data=data, page=page)
    elif node_type == 2:
        return RootNode(tree_conf, data=data, page=page)
    elif node_type == 3:
        return InternalNode(tree_conf, data=data, page=page)
