class String(ConfigValue):
    """String value.

    Is decoded as utf-8 and \\n \\t escapes should work and be preserved.
    """

    def __init__(self, optional=False, choices=None, transformer=None):
        self._required = not optional
        self._choices = choices
        self._transformer = transformer

    def deserialize(self, value):
        if value is None:
            if self._required:
                raise ValueError("Value is required")
            return None

        value = decode(value)

        if self._choices is not None and value not in self._choices:
            raise ValueError("Invalid value: %r" % value)

        if self._transformer is not None:
            transformed = self._transformer(value)
            return _TransformedValue(value, transformed)

        return value

class ConfigSchema(collections.OrderedDict):

    """Logical group of config values that correspond to a config section.

    Schemas are set up by assigning config keys with config values to
    instances. Once setup :meth:`deserialize` can be called with a dict of
    values to process. For convienience we also support :meth:`format` method
    that can used for converting the values to a dict that can be printed and
    :meth:`serialize` for converting the values to a form suitable for
    persistence.
    """

    def __init__(self, name):
        super().__init__()
        self.name = name

    def deserialize(self, values):
        """Validates the given ``values`` using the config schema.

        Returns a tuple with cleaned values and errors.
        """
        cleaned = {}
        errors = {}

        # Validate known keys
        for key, schema in self.items():
            if key in values:
                try:
                    cleaned[key] = schema.deserialize(values[key])
                except Exception as exc:
                    errors[key] = str(exc)
            else:
                # Use default if available
                try:
                    cleaned[key] = schema.deserialize(None)
                except Exception:
                    pass

        # Report unknown keys
        for key in values:
            if key not in self:
                suggestion = _did_you_mean(key, self.keys())
                if suggestion:
                    errors[key] = "Unknown setting. Did you mean %r?" % suggestion
                else:
                    errors[key] = "Unknown setting."

        return cleaned, errors

