class Integer(ConfigValue):
    """Integer value."""

    def __init__(
        self, minimum=None, maximum=None, choices=None, optional=False
    ):
        self._required = not optional
        self._minimum = minimum
        self._maximum = maximum
        self._choices = choices

    def deserialize(self, value):
        if value is None:
            if self._required:
                raise ValueError("Value is required")
            return None

        try:
            value = int(value)
        except (TypeError, ValueError):
            raise ValueError("Invalid integer value")

        if self._minimum is not None and value < self._minimum:
            raise ValueError(
                "Value must be greater than or equal to %s" % self._minimum
            )

        if self._maximum is not None and value > self._maximum:
            raise ValueError(
                "Value must be less than or equal to %s" % self._maximum
            )

        if self._choices is not None and value not in self._choices:
            raise ValueError("Value must be one of %s" % self._choices)

        return value

class Float(ConfigValue):
