@stored_property
def dependencies(self):
    """Run's the files' linker iteratively and returns a set of all library dependencies."""
    dependencies = set()
    to_process = [self]

    while to_process:
        elf = to_process.pop()
        for dependency in elf.find_direct_dependencies():
            if dependency not in dependencies:
                dependencies.add(dependency)
                # Only ELF files can have further dependencies.
                if isinstance(dependency, Elf):
                    to_process.append(dependency)

    return dependencies

@stored_property
def hash(self):
    """str: Computes a hash based on the file content, useful for file deduplication."""
    import hashlib

    hasher = hashlib.sha256()
    with open(self.path, 'rb') as f:
        for chunk in iter(lambda: f.read(1024 * 1024), b''):
            hasher.update(chunk)
    return hasher.hexdigest()

