class MechInventoryConnector(BaseConnector):
    @staticmethod
    def make_names_data(limit=None):
        try:
            config = get_mech_config(limit=limit)
        except Exception as e:
            raise InventoryError("Failed to get Mech inventory config: {0}".format(e))

        names_data = []
        seen = set()

        for line in config:
            if not line.strip():
                continue

            host = {}
            for item in line.split():
                if "=" not in item:
                    continue
                key, value = item.split("=", 1)
                host[key] = value

            if "Host" not in host or "HostName" not in host:
                continue

            name, data, groups = _make_name_data(host)

            if name in seen:
                continue
            seen.add(name)

            names_data.append((name, data, groups))

        return names_data

