@staticmethod
def from_ready_archive_status(xlog_dir):
    """Yield WalSegment objects for all .ready files in archive_status.

    This scans the given WAL directory's archive_status subdirectory and
    returns segments corresponding to files ending in `.ready`.
    """
    status_dir = path.join(xlog_dir, 'archive_status')

    try:
        entries = os.listdir(status_dir)
    except Exception:
        raise UserCritical(
            msg='problem reading archive_status directory',
            detail='Traceback is: {0}'.format(traceback.format_exc()),
            hint='report a bug')

    for entry in entries:
        if not entry.endswith('.ready'):
            continue

        ready_path = path.join(status_dir, entry[:-6])  # strip ".ready"
        yield WalSegment(ready_path, explicit=False)

