@staticmethod
def merge(files, accumulate=True):
    """Merge metrics from given mmap files.

    By default, histograms are accumulated, as per prometheus wire format.
    But if writing the merged data back to mmap files, use
    accumulate=False to avoid compound accumulation.
    """
    from collections import defaultdict

    metrics = defaultdict(lambda: defaultdict(float))
    histograms = defaultdict(lambda: defaultdict(float))
    summaries = defaultdict(lambda: defaultdict(float))

    for f in files:
        for metric in f:
            name = metric.get('name')
            labels = tuple(sorted(metric.get('labels', {}).items()))
            value = metric.get('value', 0.0)
            mtype = metric.get('type')

            if mtype == 'counter' or mtype == 'gauge':
                metrics[(name, mtype)][labels] += value

            elif mtype == 'histogram':
                # Histogram samples are expected to be bucket/count/sum style.
                # Merge by label set and accumulate bucket values.
                histograms[name][labels] += value

            elif mtype == 'summary':
                summaries[name][labels] += value

    merged = []

    for (name, mtype), samples in metrics.items():
        for labels, value in samples.items():
            merged.append({
                'name': name,
                'type': mtype,
                'labels': dict(labels),
                'value': value,
            })

    for name, samples in histograms.items():
        for labels, value in samples.items():
            merged.append({
                'name': name,
                'type': 'histogram',
                'labels': dict(labels),
                'value': value,
            })

    for name, samples in summaries.items():
        for labels, value in samples.items():
            merged.append({
                'name': name,
                'type': 'summary',
                'labels': dict(labels),
                'value': value,
            })

    return merged

