while True:
    try:
        # Process each source.
        for source_name, source in self.sources.items():
            logger.debug(f"Polling source '{source_name}'")
            try:
                artifacts = source.poll()
            except Exception:
                logger.exception(f"Error polling source '{source_name}'")
                continue

            if not artifacts:
                continue

            for artifact in artifacts:
                try:
                    # Skip whitelisted artifacts.
                    if self._is_whitelisted(artifact):
                        self.statsd.incr('whitelist')
                        continue

                    # Skip artifacts already seen.
                    if self.statedb.contains(str(artifact)):
                        logger.debug(
                            f"Reject {str(artifact)} from further processing because it is already in state."
                        )
                        self.statsd.incr('duplicate')
                        continue

                    # Send to operators.
                    delivered = False
                    for operator_name, operator in self.operators.items():
                        try:
                            logger.debug(
                                f"Sending artifact '{artifact}' to operator '{operator_name}'"
                            )
                            operator.send(artifact)
                            delivered = True
                        except Exception:
                            logger.exception(
                                f"Error sending artifact '{artifact}' to operator '{operator_name}'"
                            )

                    if delivered:
                        self.statedb.add(str(artifact))
                        self.statsd.incr('artifact')
                    else:
                        self.statsd.incr('failed')

                except Exception:
                    logger.exception(f"Unhandled error processing artifact '{artifact}'")

        # Persist state after each full pass.
        try:
            self.statedb.save()
        except Exception:
            logger.exception("Error saving state database")

    except KeyboardInterrupt:
        logger.info("Interrupted by user")
