def _luhn_checksum(self, number: str) -> str:
    """Return the Luhn check digit for ``number``."""
    total = 0
    reverse_digits = list(map(int, reversed(number)))
    for i, digit in enumerate(reverse_digits):
        if i % 2 == 0:
            total += digit
        else:
            total += self.luhn_lookup[str(digit)]
    return str((10 - (total % 10)) % 10)

