@property
def vegalite_major_version(self) -> int:
    """Return the major Vega-Lite schema version used by this chart."""
    schema = self.data.get("$schema", "")
    if not schema:
        return 2

    # Try to extract the version number from the schema URL/path.
    # Examples:
    #   https://vega.github.io/schema/vega-lite/v5.json
    #   https://vega.github.io/schema/vega-lite/v4.17.0.json
    try:
        import re

