@property
def address(self):
    bind = self.settings['bind'].get()

    # If bind is already a tuple/list, return it directly.
    if isinstance(bind, (tuple, list)):
        return bind

    # Support unix socket paths.
    if isinstance(bind, str) and bind.startswith("unix:"):
        return bind[5:]

    # Parse host:port, [ipv6]:port, or bare port.
    if isinstance(bind, str):
        if bind.startswith("["):
            # IPv6 form: [::1]:8000
            host, _, port = bind.rpartition("]:")
            host = host[1:] if host.startswith("[") else host
            return host, int(port)

        if ":" in bind:
            host, port = bind.rsplit(":", 1)
            if host == "":
                host = "0.0.0.0"
            return host, int(port)

        # Bare port
        return "0.0.0.0", int(bind)

    return bind

class LengthReader(object):
    def __init__(self, unreader, length):
        self.unreader = unreader
        self.length = length

    def read(self, size):
        if self.length <= 0:
            return b""

        if size is None or size < 0 or size > self.length:
            size = self.length

        data = self.unreader.read(size)
        if data is None:
            data = b""

        self.length -= len(data)
        return data

