while remaining > 0:
    chunk = self.reader.read(remaining)
    if not chunk:
        break
    chunks.append(chunk)
    remaining -= len(chunk)

return b"".join(chunks)

class Unreader(object):
    def __init__(self):
        self.buf = io.BytesIO()

    def chunk(self):
        raise NotImplementedError()

    def read(self, size=None):
        # Read all available data if size is not specified.
        if size is None:
            chunks = [self.buf.getvalue()]
            self.buf = io.BytesIO()

            while True:
                data = self.chunk()
                if not data:
                    break
                chunks.append(data)

            return b"".join(chunks)

        # First satisfy from the internal buffer.
        out = self.buf.read(size)
        remaining = size - len(out)

        # If we still need more, pull chunks until enough or exhausted.
        while remaining > 0:
            data = self.chunk()
            if not data:
                break

            if len(data) <= remaining:
                out += data
                remaining -= len(data)
            else:
                out += data[:remaining]
                # Save the unused remainder back into the buffer.
                self.buf = io.BytesIO(data[remaining:])
                remaining = 0

        return out

if not data:
