    def include_dirs(self):
        return [
            "{}/{}".format(
                self.ctx.include_dir,
                d.format(arch=self))
            for d in self.ctx.include_dirs]

    @property
    def target(self):
        # As of NDK r19, the toolchains installed by default with the
        # NDK may be used in-place. The make_standalone_toolchain.py script
        # is no longer needed for interfacing with arbitrary build systems.
        # See: https://developer.android.com/ndk/guides/other_build_systems
        return self.command_prefix + self.ctx.ndk_api

    @property
    def python_includes(self):
        return ':'.join(self.include_dirs)

    @property
    def ctx_libs_dir(self):
        return self.ctx.libs_dir

    @property
    def cflags(self):
        return [
            flag.format(
                target=self.target,
                ctx=self.ctx,
                python_includes=self.python_includes,
                ctx_libs_dir=self.ctx_libs_dir,
                arch=self,
            )
            for flag in (self.common_cflags + self.arch_cflags)
        ]

