                target=self.target,
                ctx=self.ctx,
                python_includes=self.python_includes,
                ctx_libs_dir=self.ctx_libs_dir,
                arch=self,
            )
            for flag in self.common_cppflags
        ]

    @property
    def ldflags(self):
        flags = self.common_ldflags + self.extra_global_link_paths
        return [
            flag.format(
                target=self.target,
                ctx=self.ctx,
                python_includes=self.python_includes,
                ctx_libs_dir=self.ctx_libs_dir,
