@property
def relative_datetime(self):
    """Return human-readable relative time string."""
    from datetime import datetime

    now = datetime.now(self.created_at.tzinfo)
    delta = now - self.created_at

    seconds = int(delta.total_seconds())
    if seconds < 0:
        seconds = 0

    if seconds < 60:
        return "just now" if seconds < 5 else "{} seconds ago".format(seconds)

    minutes = seconds // 60
    if minutes < 60:
        return "1 minute ago" if minutes == 1 else "{} minutes ago".format(minutes)

    hours = minutes // 60
    if hours < 24:
        return "1 hour ago" if hours == 1 else "{} hours ago".format(hours)

    days = hours // 24
    if days < 7:
        return "1 day ago" if days == 1 else "{} days ago".format(days)

    weeks = days // 7
    if weeks < 4:
        return "1 week ago" if weeks == 1 else "{} weeks ago".format(weeks)

    months = days // 30
    if months < 12:
        return "1 month ago" if months == 1 else "{} months ago".format(months)

    years = days // 365
    return "1 year ago" if years == 1 else "{} years ago".format(years)

