@classmethod
def _parse_narrow_link(cls, link: str) -> ParsedNarrowLink:
    """
    Returns either a dict with narrow parameters for supported links or an
    empty dict.
    """
    # NOTE: The optional stream_id link version is deprecated. The extended
    # support is for old messages.
    # We expect the fragment to be one of the following types:
    # a. narrow/stream/[{stream_id}-]{stream-name}
    # b. narrow/stream/[{stream_id}-]{stream-name}/near/{message_id}
    # c. narrow/stream/[{stream_id}-]{stream-name}/topic/
    #    {encoded.20topic.20name}
    # d. narrow/stream/[{stream_id}-]{stream-name}/topic/
    #    {encoded.20topic.20name}/near/{message_id}

    parsed = urlparse(link)
    fragment = parsed.fragment
    if not fragment.startswith("narrow/stream/"):
        return {}

    parts = fragment.split("/")
    # Expected minimum: narrow / stream / <stream>
    if len(parts) < 3:
        return {}

    encoded_stream_data = parts[2]
    decoded_stream = cls._decode_stream_data(encoded_stream_data)

    result: ParsedNarrowLink = {"narrow": fragment, "stream": decoded_stream}

    # Handle optional topic and/or near message id.
    idx = 3
    while idx < len(parts):
        part = parts[idx]
        if part == "topic" and idx + 1 < len(parts):
            result["topic_name"] = hash_util_decode(parts[idx + 1])
            idx += 2
        elif part == "near" and idx + 1 < len(parts):
            result["message_id"] = cls._decode_message_id(parts[idx + 1])
            idx += 2
        else:
            # Unsupported or malformed narrow link.
            return {}
    return result

