class PrevalenceCounter:
    def __init__(self):
        self.keyword_counts = defaultdict(int)
        self.name_counts = defaultdict(int)

    def update(self, text):
        if not text:
            return

        # Count words/phrases in a simple normalized way
        tokens = re.findall(r"[A-Za-z0-9_']+", text.lower())

        for token in tokens:
            self.keyword_counts[token] += 1

        # Heuristic: treat capitalized words as names
        # (works reasonably for simple person/place names)
        for match in re.findall(r"\b[A-Z][a-z]+(?:\s+[A-Z][a-z]+)*\b", text):
            self.name_counts[match] += 1

