                if self.read_offset < self.buffer_end_offset and self.buffer[self.read_offset] == self.LF:
                    continue
                if self.read_offset >= self.buffer_end_offset:
                    self.needs_more_data = True
                    break

                # If we just consumed the blank line, switch to content.
                self.read_state = ReadState.Content
                break

            # Read a header line.
            line_start = self.read_offset
            while self.read_offset < self.buffer_end_offset and self.buffer[self.read_offset] not in (self.CR, self.LF):
                self.read_offset += 1

            if self.read_offset >= self.buffer_end_offset:
                self.needs_more_data = True
                break

            line = bytes(self.buffer[line_start:self.read_offset]).decode(self.encoding)
            if self.buffer[self.read_offset] == self.CR:
                if self.read_offset + 1 >= self.buffer_end_offset:
                    self.needs_more_data = True
                    break
                if self.buffer[self.read_offset + 1] != self.LF:
                    raise ValueError("Invalid header line ending")
                self.read_offset += 2
            else:
