class IntStreamer(object):

    @classmethod
    def int_from_script_bytes(class_, s, require_minimal=False):
        if len(s) == 0:
            return 0

        # Bitcoin Script numbers are little-endian signed-magnitude integers.
        # The most significant byte's highest bit is the sign bit.
        v = 0
        for i, b in enumerate(s):
            v |= b << (8 * i)

        # If the sign bit is set, clear it and negate the result.
        if s[-1] & 0x80:
            v &= ~(0x80 << (8 * (len(s) - 1)))
            v = -v

        if require_minimal:
            # Minimal encoding checks:
            # - zero must be encoded as empty
            # - no redundant leading bytes
            if len(s) > 0:
                # If the most significant byte is zero or 0x80, then the
                # encoding is non-minimal unless needed for sign preservation.
                if (s[-1] & 0x7f) == 0:
                    if len(s) == 1 or (s[-2] & 0x80) == 0:
                        raise ScriptError("non-minimally encoded script number", "SCRIPT_ERR_MINIMALDATA")

        return v

