# calc target position from self.pos, pos and offset
if self.handle is None:
    raise IOError('seek on closed handle')

if offset == io.SEEK_SET:
    target = pos
elif offset == io.SEEK_CUR:
    target = self.pos + pos
elif offset == io.SEEK_END:
    target = self.size + pos
else:
    raise ValueError('invalid seek mode: {0}'.format(offset))

if target < 0:
    raise IOError('negative seek position {0}'.format(target))

# If seeking backwards, or if the underlying stream cannot seek,
# reopen and skip forward.
if target < self.pos:
    self.reset()
    self.open()
elif target == self.pos:
    return self.pos

# Skip forward to target position
to_skip = target - self.pos
if to_skip > 0:
    while to_skip > 0:
        chunk = self.handle.read(min(self.CHUNK_SIZE, to_skip))
        if not chunk:
            break
        skipped = len(chunk)
        self.pos += skipped
        to_skip -= skipped

return self.pos

