class CpuResource(Resource[float], resource_id="cpu"):
    @classmethod
    def from_spec(cls, spec: t.Any) -> float:
        """
        Convert spec to CpuResource.

        spec can be a float, int or string.
        - 1.0 -> 1.0
        - 1 -> 1.0
        - "1" -> 1.0
        - "10m" -> 0.01
        """
        if isinstance(spec, (int, float)):
            return float(spec)

        if isinstance(spec, str):
            value = spec.strip()
            if value.endswith("m"):
                try:
                    return float(value[:-1]) / 1000.0
                except ValueError as e:
                    raise BentoMLConfigException(
                        f"Invalid cpu resource specification: {spec!r}"
                    ) from e
            try:
                return float(value)
            except ValueError as e:
                raise BentoMLConfigException(
                    f"Invalid cpu resource specification: {spec!r}"
                ) from e

        raise BentoMLConfigException(
            f"Invalid cpu resource specification: {spec!r}"
        )

@classmethod
def validate(cls, val: float):
    if not isinstance(val, (int, float)):
        raise TypeError("cpu must be int or float")
    if val <= 0:
        raise BentoMLConfigException("CPU resource limit must be greater than 0.")
    return float(val)

