import os
import yaml

if not os.path.exists(path):
    raise BentoMLConfigException(f"Config file not found: {path}")

try:
    with open(path, "r", encoding="utf-8") as f:
        config = yaml.safe_load(f)
except Exception as e:
    raise BentoMLConfigException(f"Failed to load config file {path}: {e}") from e

if config is None:
    return {}

if not isinstance(config, dict):
    raise BentoMLConfigException(
        f"Config file must contain a mapping at the top level: {path}"
    )

return config

class DefaultStrategy(Strategy):
    @classmethod
    def get_worker_count(
        cls,
        runnable_class: t.Type[Runnable],
        resource_request: dict[str, t.Any] | None,
        workers_per_resource: int | float,
    ) -> int:
        # If no resource request is provided, default to a single worker.
        if not resource_request:
            return 1

        # Determine how many workers each requested resource can support.
        # We use the minimum across all requested resources so we don't exceed
        # the capacity of any single resource type.
        worker_counts: list[int] = []

        for resource_kind, requested in resource_request.items():
            if requested is None:
                continue

            # "system" means use the full available system resource.
            if requested == "system":
                requested_amount = get_resource(system_resources(), resource_kind)
            else:
                requested_amount = get_resource(resource_request, resource_kind)

            if requested_amount is None:
                continue

            # Convert resource amount to a numeric value when possible.
            # Most resource types in BentoML are numeric or behave like numeric
            # quantities for scheduling purposes.
            try:
                amount = float(requested_amount)
            except (TypeError, ValueError):
                # If the resource cannot be interpreted numerically, fall back
                # to a single worker for safety.
                return 1

            worker_counts.append(max(1, int(amount * workers_per_resource)))

        if not worker_counts:
            return 1

        return max(1, min(worker_counts))

@classmethod
def from_payload(
    cls,
    payload: Payload,
) -> ext.NpNDArray:
    if payload.meta.get("format") == "pickle5":
        pickle_bytes_str = t.cast(str, payload.meta["pickle_bytes_str"])
        indices = t.cast(list[int], payload.meta["indices"])
        main_bytes = base64.b64decode(pickle_bytes_str.encode("ascii"))
        return t.cast(
            ext.NpNDArray,
            pep574_loads(main_bytes, payload.data, indices),
        )

    return t.cast(ext.NpNDArray, fixed_torch_loads(payload.data))

class NdarrayContainer(DataContainer["ext.NpNDArray", "ext.NpNDArray"]):
    @classmethod
    def batches_to_batch(
        cls,
        batches: t.Sequence[ext.NpNDArray],
        batch_dim: int = 0,
    ) -> tuple[ext.NpNDArray, list[int]]:
        # numpy.concatenate may consume lots of memory, need optimization later
        if not batches:
            raise ValueError("batches must not be empty")

        if len(batches) == 1:
            batch = batches[0]
            return batch, [batch.shape[batch_dim]]

        sizes = [batch.shape[batch_dim] for batch in batches]
        batch = np.concatenate(batches, axis=batch_dim)
        return batch, sizes

@classmethod
def to_payload(
    cls,
    batch: ext.NpNDArray,
    batch_dim: int,
) -> Payload:
    # skip 0-dimensional array
    if batch.ndim == 0:
        data = pickle.dumps(batch, protocol=5)
        return Payload(
            data=data,
            meta={"indices": [], "batch_dim": batch_dim},
            container=cls.__name__,
            batch_size=1,
        )

    data, buffer_bytes, indices = pep574_dumps(batch)
    return Payload(
        data=data + buffer_bytes,
        meta={"indices": indices, "batch_dim": batch_dim},
        container=cls.__name__,
        batch_size=batch.shape[batch_dim],
    )

@classmethod
def batch_to_payloads(
    cls,
    batch: ext.NpNDArray,
    indices: t.Sequence[int],
    batch_dim: int = 0,
) -> list[Payload]:
    batches = cls.batch_to_batches(batch, indices, batch_dim=batch_dim)
    return [cls.to_payload(subbatch, batch_dim=batch_dim) for subbatch in batches]

@classmethod
def from_payload(
    cls,
    payload: Payload,
) -> ext.PdDataFrame:
    meta = payload.meta

    if meta.get("format") != "pickle5":
        raise ValueError(f"Unsupported payload format: {meta.get('format')}")

    if meta.get("with_buffer"):
        bs = base64.b64decode(t.cast(str, meta["pickle_bytes_str"]))
        indices = t.cast(list[int], meta["indices"])
        return pep574_loads(bs, payload.data, indices)

    return fixed_torch_loads(payload.data)

@classmethod
def to_payload(
    cls,
    batch: ext.PdDataFrame | ext.PdSeries,
    batch_dim: int,
) -> Payload:
    assert (
        batch_dim == 0
    ), "PandasDataFrameContainer does not support batch_dim other than 0"

    data, buffer_bytes, indices = pep574_dumps(batch)
    meta: dict[str, bool | int | float | str | list[int]] = {
        "indices": indices,
        "has_buffers": bool(buffer_bytes),
    }
    if buffer_bytes:
        meta["buffer_length"] = len(buffer_bytes)

    return Payload(
        data=data + buffer_bytes,
        meta=meta,
        container=cls.__name__,
        batch_size=len(batch),
    )

@classmethod
def batch_to_payloads(
    cls,
    batch: ext.PdDataFrame,
    indices: t.Sequence[int],
    batch_dim: int = 0,
) -> list[Payload]:
    assert (
        batch_dim == 0
    ), "PandasDataFrameContainer does not support batch_dim other than 0"

    batches = cls.batch_to_batches(batch, indices, batch_dim=batch_dim)
    return [cls.to_payload(subbatch, batch_dim=batch_dim) for subbatch in batches]

@classmethod
def from_batch_payloads(
    cls,
    payloads: t.Sequence[Payload],
    batch_dim: int = 0,
) -> t.Tuple["ext.NpNDArray", list[int]]:
    batches = [cls.from_payload(payload) for payload in payloads]
    return cls.batches_to_batch(batches, batch_dim)

@classmethod
def from_batch_payloads(  # pylint: disable=arguments-differ
    cls,
    payloads: t.Sequence[Payload],
    batch_dim: int = 0,
) -> tuple[ext.PdDataFrame, list[int]]:
    assert (
        batch_dim == 0
    ), "PandasDataFrameContainer does not support batch_dim other than 0"

    batches = [cls.from_payload(payload) for payload in payloads]
    return cls.batches_to_batch(batches, batch_dim)

@classmethod
def to_payload(cls, batch: t.Any, batch_dim: int) -> Payload:
    assert (
        batch_dim == 0
    ), "Default Runner DataContainer does not support batch_dim other than 0"

    data = pickle.dumps(batch)
    return Payload(
        data=data,
        meta={},
        container=cls.__name__,
        batch_size=len(batch) if hasattr(batch, "__len__") else -1,
    )

@classmethod
def result_to_console_output(cls, result: HeartbleedScanResult) -> List[str]:
    if result.is_vulnerable_to_heartbleed:
        return ["VULNERABLE - Server is vulnerable to Heartbleed"]
    return ["OK - Not vulnerable to Heartbleed"]

@classmethod
def result_to_console_output(cls, result: SessionRenegotiationScanResult) -> List[str]:
    output = []

    if result.supports_secure_renegotiation:
        output.append("Secure renegotiation: supported")
    else:
        output.append("Secure renegotiation: not supported")

    if result.is_vulnerable_to_client_renegotiation_dos:
        output.append("Client-initiated renegotiation: supported (vulnerable to DoS)")
    else:
        output.append("Client-initiated renegotiation: not supported")

    return output

@classmethod
def parse_server_string(cls, server_str: str) -> Tuple[str, Optional[str], Optional[int]]:
    # Extract ip from target
    server_str = server_str.strip()

    if not server_str:
        raise ValueError(cls.SERVER_STRING_ERROR_BAD_PORT)

    host = server_str
    ip: Optional[str] = None
    port: Optional[int] = None

    # Handle optional "{ip}" suffix
    if "{" in server_str and server_str.endswith("}"):
        host_part, ip_part = server_str.rsplit("{", 1)
        host = host_part.strip()
        ip = ip_part[:-1].strip()  # remove trailing "}"
        if not ip:
            ip = None

    # Parse host and port
    if host.startswith("["):
        # IPv6 in brackets: [::1]:8080
        if "]" not in host:
            raise ValueError(cls.SERVER_STRING_ERROR_BAD_PORT)
        end = host.rfind("]")
        host_only = host[1:end]
        remainder = host[end + 1 :].strip()
        if remainder:
            if not remainder.startswith(":"):
                raise ValueError(cls.SERVER_STRING_ERROR_BAD_PORT)
            port_str = remainder[1:].strip()
            try:
                port = int(port_str)
            except ValueError:
                raise ValueError(cls.SERVER_STRING_ERROR_BAD_PORT) from None
        host = host_only
    else:
        # Split on last colon to support IPv6 without brackets only when no port is present
        if ":" in host:
            host_only, port_str = host.rsplit(":", 1)
            # If host_only still contains ":" then this is likely an unbracketed IPv6 address with no port
            if ":" in host_only:
                host = host
            else:
                host = host_only.strip()
                try:
                    port = int(port_str.strip())
                except ValueError:
                    raise ValueError(cls.SERVER_STRING_ERROR_BAD_PORT) from None

    if not host:
        raise ValueError(cls.SERVER_STRING_ERROR_BAD_PORT)

    return host, ip, port

