parsed_location = urlsplit(location)

# Relative redirect: keep only the path/query/fragment
if not parsed_location.scheme and not parsed_location.netloc:
    return parsed_location.path or "/"

# Absolute redirect: only accept redirects to the same host/port
location_host = parsed_location.hostname
location_port = parsed_location.port

if location_host is None:
    return None

# If no port is specified, infer from the scheme
if location_port is None:
    if parsed_location.scheme == "https":
        location_port = 443
    elif parsed_location.scheme == "http":
        location_port = 80

