@classmethod
def get_distrust_timeline(
    cls, verified_certificate_chain: List[Certificate]
) -> Optional[SymantecDistrustTimelineEnum]:
    # Symantec distrust applies only to CA certificates in the chain.
    # If any CA public key matches the whitelist, the chain is exempt.
    for certificate in verified_certificate_chain[1:]:
        pubkey_sha256 = binascii.hexlify(get_public_key_sha256(certificate)).decode("ascii")

        if pubkey_sha256 in cls._CA_KEYS_WHITELIST:
            return None

        if pubkey_sha256 in cls._CA_KEYS_BLACKLIST:
            # Google/Mozilla distrust timeline:
            # - March 2018 for certificates issued before 2016-06-01
            # - September 2018 for all remaining Symantec-issued certs
            not_before = verified_certificate_chain[0].not_valid_before
            if not_before < datetime(2016, 6, 1):
                return SymantecDistrustTimelineEnum.MARCH_2018
            return SymantecDistrustTimelineEnum.SEPTEMBER_2018

    return None

try:
    san_extension = certificate.extensions.get_extension_for_oid(ExtensionOID.SUBJECT_ALTERNATIVE_NAME).value
except ExtensionNotFound:
    return SubjectAlternativeNameExtension(dns_names=[], ip_addresses=[])

san_extension = cast(SubjectAlternativeName, san_extension)

dns_names = [name.value for name in san_extension.get_values_for_type(DNSName)]
ip_addresses = [str(ip) for ip in san_extension.get_values_for_type(IPAddress)]

return SubjectAlternativeNameExtension(dns_names=dns_names, ip_addresses=ip_addresses)

